// Compute Offered Courses - adapted for Postgres row-level input
// Uses $('NodeName') to reference each upstream query directly

const studentRows = $('Read Demand Data').all().map(i => i.json);
const studyPlanRows = $('Read Study Plan').all().map(i => i.json);
const constraintRows = $('Read Constraints').all().map(i => i.json);
const electiveRows = $('Read Electives').all().map(i => i.json);

// Build constraints lookup
const constraintsData = {};
for (const c of constraintRows) constraintsData[c.constraint_id] = c;

// Build elective groups
const electiveGroupsData = {};
for (const e of electiveRows) {
    const prog = e.program_code;
    const group = e.group_code;
    if (!electiveGroupsData[prog]) electiveGroupsData[prog] = {};
    if (!electiveGroupsData[prog][group]) electiveGroupsData[prog][group] = [];
    electiveGroupsData[prog][group].push({ course_code: e.course_code, course_name: e.course_name || '' });
}

// Count failed courses across all students
const failedCounts = {};
for (const student of studentRows) {
    const grades = student.grades;
    if (Array.isArray(grades)) {
        for (const g of grades) {
            if (g && ['F', 'FW'].includes(String(g.grade))) {
                failedCounts[g.course_code] = (failedCounts[g.course_code] || 0) + 1;
            }
        }
    }
}

const targetSemester = 'Fall';
const failThreshold = constraintsData['C004'] ? parseInt(constraintsData['C004'].value) : 30;

const groupedOfferedCourses = {};
const offeredCourseCodesByProgram = {};

for (const entry of studyPlanRows) {
    const program = entry.program_code;
    const cc = String(entry.course_code || '').trim();
    if (!cc) continue;

    if (!groupedOfferedCourses[program]) {
        groupedOfferedCourses[program] = [];
        offeredCourseCodesByProgram[program] = new Set();
    }

    const semesterNumber = parseInt(entry.semester_number, 10);
    const isOdd = semesterNumber % 2 !== 0;
    const isEven = semesterNumber % 2 === 0;
    const isTargetSeason = (targetSemester === 'Fall' && isOdd) || (targetSemester === 'Spring' && isEven);

    if (isTargetSeason) {
        if (/^E\d+$/.test(cc) && electiveGroupsData[program] && electiveGroupsData[program][cc]) {
            for (const elective of electiveGroupsData[program][cc]) {
                if (!offeredCourseCodesByProgram[program].has(elective.course_code)) {
                    groupedOfferedCourses[program].push({
                        course_code: elective.course_code,
                        course_name: elective.course_name,
                        credits: entry.credits,
                        type: 'Elective Offering',
                        elective_group: cc,
                        semester_offered: String(semesterNumber),
                        lec_hours: parseInt(entry.lec_hours) || 0,
                        tut_hours: parseInt(entry.tut_hours) || 0,
                        lab_hours: parseInt(entry.lab_hours) || 0
                    });
                    offeredCourseCodesByProgram[program].add(elective.course_code);
                }
            }
        } else if (!cc.startsWith('UC') && !cc.startsWith('UE')) {
            if (!offeredCourseCodesByProgram[program].has(cc)) {
                groupedOfferedCourses[program].push({
                    course_code: cc,
                    course_name: entry.course_name || '',
                    credits: entry.credits,
                    type: 'Standard Offering',
                    semester_offered: String(semesterNumber),
                    lec_hours: parseInt(entry.lec_hours) || 0,
                    tut_hours: parseInt(entry.tut_hours) || 0,
                    lab_hours: parseInt(entry.lab_hours) || 0
                });
                offeredCourseCodesByProgram[program].add(cc);
            }
        }
    }
}

// Force open courses with high failure rates
for (const [courseCode, count] of Object.entries(failedCounts)) {
    if (count > failThreshold) {
        const planEntries = studyPlanRows.filter(sp => sp.course_code === courseCode);
        for (const planEntry of planEntries) {
            const program = planEntry.program_code;
            if (!groupedOfferedCourses[program]) {
                groupedOfferedCourses[program] = [];
                offeredCourseCodesByProgram[program] = new Set();
            }
            if (!offeredCourseCodesByProgram[program].has(courseCode)) {
                groupedOfferedCourses[program].push({
                    course_code: courseCode,
                    course_name: planEntry.course_name || '',
                    credits: planEntry.credits,
                    type: 'Forced Open (>' + failThreshold + ' Fails Exception)',
                    failing_student_count: count,
                    semester_offered: String(planEntry.semester_number),
                    lec_hours: parseInt(planEntry.lec_hours) || 0,
                    tut_hours: parseInt(planEntry.tut_hours) || 0,
                    lab_hours: parseInt(planEntry.lab_hours) || 0
                });
                offeredCourseCodesByProgram[program].add(courseCode);
            }
        }
    }
}

return [{ json: { offered_courses: groupedOfferedCourses, target_semester: targetSemester } }];

// CSP Greedy Placement Solver v2 — Constraint-Aware
// HC1: No two courses in same program+year share day+period
// HC2: No two courses occupy same room at day+period
// HC3: Cross-program shared courses scheduled once, 4-row output
// HC4: Demand > room capacity → split into sections

const offeredCourses = $('Compute Offered Courses').first().json.offered_courses;
const roomItems = $('Read Rooms').all().map(i => i.json);
const studentRows = $('Read Demand Data').all().map(i => i.json);
const prereqRows = $('Read Prerequisites').all().map(i => i.json);
const studyPlanRows = $('Read Study Plan').all().map(i => i.json);
const webhookData = $('Advisor Webhook').first().json;
const term = (webhookData.body && webhookData.body.term) || '2252';

const halls = roomItems.filter(r => String(r.room_type).toUpperCase() === 'HALL').sort((a, b) => b.capacity - a.capacity);
const labs = roomItems.filter(r => String(r.room_type).toUpperCase() === 'LAB').sort((a, b) => b.capacity - a.capacity);
const DAYS = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday'];
const PERIODS = [1, 2, 3, 4];

function semToYear(sem) { return 'Y' + Math.ceil(parseInt(sem, 10) / 2); }

const prereqMap = {};
for (const p of prereqRows) {
  if (p.condition === 'NONE' || p.prerequisite_code === 'None' || p.prerequisite_code === p.course_code) continue;
  if (!prereqMap[p.course_code]) prereqMap[p.course_code] = [];
  prereqMap[p.course_code].push(p);
}

const courseHours = {};
for (const sp of studyPlanRows) {
  const cc = sp.course_code;
  if (!courseHours[cc]) {
    courseHours[cc] = { lec: parseInt(sp.lec_hours) || 0, tut: parseInt(sp.tut_hours) || 0, lab: parseInt(sp.lab_hours) || 0 };
  }
}

const studentPassed = {};
const studentProgram = {};
for (const s of studentRows) {
  const sid = s.student_id;
  studentProgram[sid] = s.program_code;
  studentPassed[sid] = new Set();
  const grades = Array.isArray(s.grades) ? s.grades : [];
  for (const g of grades) {
    if (g && !['F', 'FW', 'W', 'U'].includes(String(g.grade))) {
      studentPassed[sid].add(g.course_code);
    }
  }
}

function isEligible(studentId, courseCode) {
  if (studentPassed[studentId].has(courseCode)) return false;
  const prereqs = prereqMap[courseCode];
  if (!prereqs || prereqs.length === 0) return true;
  const andP = prereqs.filter(p => p.condition === 'AND' || p.condition === 'MANDATORY');
  const orP = prereqs.filter(p => p.condition === 'OR');
  for (const ap of andP) { if (!studentPassed[studentId].has(ap.prerequisite_code)) return false; }
  if (orP.length > 0 && !orP.some(op => studentPassed[studentId].has(op.prerequisite_code))) return false;
  return true;
}

const courseRegistry = {};
if (offeredCourses && typeof offeredCourses === 'object') {
  for (const [program, courses] of Object.entries(offeredCourses)) {
    if (!Array.isArray(courses)) continue;
    for (const course of courses) {
      const cc = course.course_code;
      if (!courseRegistry[cc]) {
        const hours = courseHours[cc] || {};
        courseRegistry[cc] = { course_code: cc, course_name: course.course_name || '', credits: course.credits || 3, programs: {}, lec_hours: hours.lec || 0, tut_hours: hours.tut || 0, lab_hours: hours.lab || 0 };
      }
      const yearGroup = semToYear(course.semester_offered);
      if (!courseRegistry[cc].programs[program]) courseRegistry[cc].programs[program] = new Set();
      courseRegistry[cc].programs[program].add(yearGroup);
    }
  }
}

const courseDemand = {};
for (const [cc, reg] of Object.entries(courseRegistry)) {
  let demand = 0;
  for (const sid of Object.keys(studentPassed)) {
    const prog = studentProgram[sid];
    if (reg.programs[prog] && isEligible(sid, cc)) demand++;
  }
  courseDemand[cc] = Math.max(demand, 1);
}

const maxHallCap = halls.length > 0 ? halls[0].capacity : 120;
const maxLabCap = labs.length > 0 ? labs[0].capacity : 60;
const placementQueue = [];

for (const [cc, reg] of Object.entries(courseRegistry)) {
  const demand = courseDemand[cc];
  const lecSec = Math.ceil(demand / maxHallCap);
  for (let s = 0; s < lecSec; s++) {
    placementQueue.push({ course_code: cc, course_name: reg.course_name, credits: reg.credits, programs: reg.programs, component: 'LEC', sectionIndex: s, totalSections: lecSec, estimatedDemand: Math.ceil(demand / lecSec) });
  }
  if (reg.tut_hours > 0) {
    const tutSec = Math.ceil(demand / maxHallCap);
    for (let s = 0; s < tutSec; s++) {
      placementQueue.push({ course_code: cc, course_name: reg.course_name, credits: reg.credits, programs: reg.programs, component: 'TUT', sectionIndex: s, totalSections: tutSec, estimatedDemand: Math.ceil(demand / tutSec) });
    }
  }
  if (reg.lab_hours > 0) {
    const labSec = Math.ceil(demand / maxLabCap);
    for (let s = 0; s < labSec; s++) {
      placementQueue.push({ course_code: cc, course_name: reg.course_name, credits: reg.credits, programs: reg.programs, component: 'LAB', sectionIndex: s, totalSections: labSec, estimatedDemand: Math.ceil(demand / labSec) });
    }
  }
}

placementQueue.sort((a, b) => b.estimatedDemand - a.estimatedDemand);

const programYearSlots = {};
const roomSlots = {};
DAYS.forEach(d => { PERIODS.forEach(p => { roomSlots[d + '_' + p] = new Set(); }); });

function slotKey(day, period) { return day + '_' + period; }
function getPYKeys(programs) {
  const keys = [];
  for (const [prog, yearSet] of Object.entries(programs)) {
    for (const year of yearSet) keys.push(prog + '_' + year);
  }
  return keys;
}

const schedule = [];
const alerts = [];

for (const section of placementQueue) {
  const roomPool = section.component === 'LAB' ? labs : halls;
  const pyKeys = getPYKeys(section.programs);
  let placed = false;

  for (const day of DAYS) {
    if (placed) break;
    for (const period of PERIODS) {
      if (placed) break;
      const sk = slotKey(day, period);
      let conflict = false;
      for (const pyk of pyKeys) {
        if (!programYearSlots[pyk]) programYearSlots[pyk] = new Set();
        if (programYearSlots[pyk].has(sk)) { conflict = true; break; }
      }
      if (conflict) continue;
      for (const room of roomPool) {
        if (!roomSlots[sk].has(room.room_id) && room.capacity >= section.estimatedDemand) {
          roomSlots[sk].add(room.room_id);
          for (const pyk of pyKeys) {
            if (!programYearSlots[pyk]) programYearSlots[pyk] = new Set();
            programYearSlots[pyk].add(sk);
          }
          for (const [prog] of Object.entries(section.programs)) {
            schedule.push({ course_code: section.course_code, course_name: section.course_name, program_code: prog, section: section.component.charAt(0) + (section.sectionIndex + 1) + prog.charAt(0), component: section.component, day: day, period: period, room_id: room.room_id, capacity: room.capacity, enrolled: 0, instructor: null, term: term });
          }
          placed = true;
          break;
        }
      }
    }
  }
  if (!placed) {
    alerts.push({ course_code: section.course_code, component: section.component, sectionIndex: section.sectionIndex, programs: Object.keys(section.programs), issue: 'NO_SLOT_AVAILABLE', message: 'Could not place ' + section.course_code + ' (' + section.component + ' section ' + (section.sectionIndex + 1) + ')' });
  }
}

// Build INSERT SQL — writes as 'draft' status
const esc = (v) => { if (v == null) return 'NULL'; const s = String(v).trim(); if (s === '') return 'NULL'; return "'" + s.replace(/'/g, "''") + "'"; };
let insert_sql = 'SELECT 1;';
if (schedule.length > 0) {
  const vals = schedule.map(s => '(' + esc(s.course_code) + ', ' + esc(s.course_name) + ', ' + esc(s.program_code) + ', ' + esc(s.section) + ', ' + esc(s.component) + ', ' + esc(s.day) + ', ' + s.period + ', ' + esc(s.room_id) + ', ' + s.capacity + ', ' + s.enrolled + ', ' + (s.instructor ? esc(s.instructor) : 'NULL') + ', ' + esc(s.term) + ', ' + "'draft'" + ')').join(',\n');
  insert_sql = 'INSERT INTO generated_schedule (course_code, course_name, program_code, section, component, day, period, room_id, capacity, enrolled, instructor, term, status) VALUES\n' + vals + ';';
}

const progCounts = {};
for (const s of schedule) progCounts[s.program_code] = (progCounts[s.program_code] || 0) + 1;

return [{ json: { schedule, alerts, total_placed: schedule.length, total_unique_courses: Object.keys(courseRegistry).length, total_unique_slots: new Set(schedule.map(s => s.day + '_' + s.period + '_' + s.room_id)).size, total_alerts: alerts.length, program_breakdown: progCounts, demand_matrix: courseDemand, insert_sql } }];

// Format schedule rows into a clean response for the UI
const rows = $input.all().map(i => i.json);
const program = $('View Schedule Webhook').first().json.query?.program || 'ALL';

const filtered = program === 'ALL' ? rows : rows.filter(r => r.program_code === program);

return [{ json: {
  schedule: filtered,
  total: filtered.length,
  programs: [...new Set(filtered.map(r => r.program_code))].sort(),
  rooms: [...new Set(filtered.map(r => r.room_id))].sort()
}}];
